1	export type Cell = [number, number];
2	
3	const MIN_NEIGHBORS_TO_SURVIVE = 2;
4	const MAX_NEIGHBORS_TO_SURVIVE = 3;
5	
6	function isNeighbor(a: Cell, b: Cell): boolean {
7	  const [ax, ay] = a;
8	  const [bx, by] = b;
9	  if (ax === bx && ay === by) return false;
10	  return Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
11	}
12	
13	function countLiveNeighbors(cell: Cell, cells: Cell[]): number {
14	  return cells.filter((other) => isNeighbor(cell, other)).length;
15	}
16	
17	function survives(cell: Cell, cells: Cell[]): boolean {
18	  const count = countLiveNeighbors(cell, cells);
19	  return count >= MIN_NEIGHBORS_TO_SURVIVE && count <= MAX_NEIGHBORS_TO_SURVIVE;
20	}
21	
22	export function nextGeneration(cells: Cell[]): Cell[] {
23	  return cells.filter((cell) => survives(cell, cells));
24	}
